// ─── ナビゲーション定義 ───────────────────────────────────────────────────────

const NAV_ITEMS = [
  { to: "/services", SVG: Nav1SVG },
  { to: "/price",    SVG: Nav2SVG },
  { to: "/work",     SVG: Nav3SVG },
  { to: "/about",    SVG: Nav4SVG },
  { to: "/blog",     SVG: Nav5SVG },
];

// ─── メインコンポーネント ─────────────────────────────────────────────────────

type NavigationProps = {
  isHero?: boolean;
};

const Navigation = ({ isHero = false }: NavigationProps) => {
  const [menuOpen, setMenuOpen] = useState(false);

  useEffect(() => {
    if (menuOpen) document.body.style.overflow = "hidden";
    else document.body.style.overflow = "";
    return () => { document.body.style.overflow = ""; };
  }, [menuOpen]);

  const navColor   = isHero ? "#ffffff" : "#000000";
  const logoSrc    = isHero ? "/images/logo_dark.svg" : "/images/logo_light.svg";
  const burgerWrap = isHero ? "border-white/25 bg-white/10" : "border-foreground/20 bg-white/70";
  const burgerLine = isHero ? "bg-white" : "bg-foreground";

  return (
    <>
      {/* ヘッダー */}
      <header className="fixed top-0 left-0 right-0 z-50 pointer-events-none">
        <div className="container mx-auto px-4 py-8 flex items-start justify-between">
          <Link to="/" className="pointer-events-auto">
            <img
              src={logoSrc}
              alt="ホームページ制作 ONE DESIGN ロゴ"
              className="w-[220px] block"
            />
          </Link>
        </div>

        {/* ハンバーガー */}
        <button
          onClick={() => setMenuOpen(true)}
          className={`lg:hidden pointer-events-auto fixed top-6 right-6 z-[70]
            w-11 h-11 rounded-full border backdrop-blur-md
            shadow-[0_8px_30px_rgba(0,0,0,0.12)]
            transition hover:scale-[1.03]
            ${burgerWrap}`}
        >
          <div className="relative w-full h-full">
            <span className={`absolute left-3 right-3 top-[15px] h-px ${burgerLine}`} />
            <span className={`absolute left-3 right-3 top-[21px] h-px ${burgerLine}`} />
            <span className={`absolute left-3 right-3 top-[27px] h-px ${burgerLine}`} />
          </div>
        </button>

        {/* PCナビ */}
        <div className="fixed top-0 right-0 z-[60] pointer-events-none">
          <div className="pointer-events-auto px-8 py-8">
            <nav className="hidden lg:flex items-center gap-10 text-sm">
              {NAV_ITEMS.map(({ to, SVG }) => (
                <Link key={to} to={to} className="opacity-90 hover:opacity-60 transition">
                  <SVG color={navColor} />
                </Link>
              ))}
              <div className="flex items-center gap-4">
                <Link
                  to="/freediagnosis"
                  style={{ color: navColor, borderColor: navColor }}
                  className="whitespace-nowrap rounded-full px-4 py-2 text-sm border backdrop-blur-md"
                >
                  無料診断
                </Link>
                <Link
                  to="/contact"
                  style={{ color: navColor, borderColor: navColor }}
                  className="whitespace-nowrap rounded-full px-4 py-2 text-sm border"
                >
                  相談する
                </Link>
              </div>
            </nav>
          </div>
        </div>
      </header>

      {/* モバイルメニュー */}
      <div
        className={`fixed inset-0 z-[80] transition-opacity duration-300
          ${menuOpen ? "opacity-100" : "opacity-0 pointer-events-none"}`}
      >
        <div
          className="absolute inset-0 bg-black/45 backdrop-blur-md"
          onClick={() => setMenuOpen(false)}
        />
        <div
          className={`absolute right-0 top-0 h-full w-[86%] max-w-sm
            bg-neutral-950/70 backdrop-blur-xl border-l border-white/10
            transition-transform duration-500 ease-[cubic-bezier(0.22,1,0.36,1)]
            ${menuOpen ? "translate-x-0" : "translate-x-full"}`}
        >
          <button
            onClick={() => setMenuOpen(false)}
            className="absolute top-6 right-6 w-11 h-11 rounded-full border border-white/15 flex items-center justify-center"
          >
            <X className="w-5 h-5 text-white" />
          </button>

          <div className="pt-24 px-7 space-y-6">
            {NAV_ITEMS.map(({ to, SVG }) => (
              <Link
                key={to}
                to={to}
                onClick={() => setMenuOpen(false)}
                className="block opacity-90 hover:opacity-60 transition"
              >
                {/* モバイルメニューは常に白（ダーク背景） */}
                <SVG color="#ffffff" />
              </Link>
            ))}
          </div>
        </div>
      </div>
    </>
  );
};

export default Navigation;
